#!/bin/bash
# AEON LIVE SDR BRIDGE
# Connects physical RTL-SDR hardware to the Aeon Monitor aesthetic.

# Colors for the bridge output
CYAN="\x1b[38;5;51m"
AMBER="\x1b[38;5;214m"
RESET="\x1b[0m"
BOLD="\x1b[1m"

echo -e "${CYAN}${BOLD}━┫ AEON LIVE SDR BRIDGE ACTIVE ┣━${RESET}"

# Configuration
FREQ=${1:-162400000} # Default to NOAA or local weather
RATE=2048000
FFT_SIZE=512
ROWS=40
OUT_FRAME="spectrum_waterfall.frame"

if ! command -v rtl_sdr &> /dev/null; then
    echo -e "${AMBER}ERROR: rtl_sdr not found. Please install rtl-sdr tools.${RESET}"
    exit 1
fi

echo -e "${CYAN}  TUNING TO: ${AMBER}${FREQ} Hz${RESET}"
echo -e "${CYAN}  SAMPLING:  ${AMBER}${RATE} Hz${RESET}"
echo -e "${CYAN}  PROJECTOR: ${AMBER}${OUT_FRAME}${RESET}"

# Start the pipeline:
# rtl_sdr (raw IQ) -> iq-waterfall-frame (FFT) -> spectrum_waterfall.frame
# We run in a loop to keep the file fresh.
while true; do
    rtl_sdr -f "$FREQ" -s "$RATE" -n "$((RATE / 2))" - 2>/dev/null | 
    ./target/release/iq-waterfall-frame 
        --input - 
        --output "$OUT_FRAME" 
        --iq-rate "$RATE" 
        --center-hz "$FREQ" 
        --fft-size "$FFT_SIZE" 
        --rows "$ROWS" 
        --source-id "rtl_sdr_live"
    sleep 0.1
done
